    16→namespace mlir::iree_compiler {
    17→
    18→#define GEN_PASS_DEF_LLVMCPU2DSCALABLETO1DSCALABLEPASS
    19→#include "iree/compiler/Codegen/LLVMCPU/Passes.h.inc"
    20→
    21→namespace {
    22→
    23→/// Currently, IREE requires `lowering_config`s to be propagated to all compute
    24→/// ops within a dispatch region. This can be problematic for SME which only
    25→/// supports 2D scalable outer product operations -- if an operation cannot be
    26→/// lowered to an outer product, we can only scalably vectorize it in one
    27→/// dimension.
    28→///
    29→/// The solution here is this pass (`2d-scalable-to-1d-scalable`) that runs just
    30→/// before vectorization, that drops unsupported scalable tile/vector sizes,
    31→/// producing loops of ops that will only be vectorized scalably in one
    32→/// dimension. This allows earlier passes like `tile-and-fuse` to still function
    33→/// correctly.
    34→///
    35→/// Take this simple example:
    36→///
    37→/// ```mlir
    38→/// // Lowering configs propagated (from matmul):
    39→/// linalg.fill {lowering_config = [[4], [4]]
    40→/// linalg.matmul {lowering_config = [[4], [4], 1]
    41→/// linalg.generic {lowering_config = [[4], [4]]
    42→/// ```
    43→/// Here the `linalg.generic` cannot be vectorized with 2D scalable vectors.
    44→///
    45→/// After `tile-and-fuse` (which requires consistent lowering configs):
    46→/// ```mlir
    47→/// scf.for i in range(0, 1000) step 4 x vscale {
    48→///   scf.for j in range(0, 2000) step 4 x vscale {
    49→///     linalg.fill {lowering_config = [[4], [4]]
    50→///     for k in range(0, 100) step 1 {
    51→///       linalg.matmul {lowering_config = [[4], [4], 1]
    52→///     }
    53→///     // 2D scalable vectorization unsupported here:
    54→///     linalg.generic {lowering_config = [[4], [4]]
    55→///   }
    56→/// }
    57→/// ```
    58→///
    59→/// Unsupported scalability removed (by `2d-scalable-to-1d-scalable`):
    60→/// ```mlir
    61→/// scf.for i in range(0, 1000) step 4 x vscale {
    62→///   scf.for j in range(0, 2000) step 4 x vscale {
    63→///     linalg.fill {lowering_config = [[4], [4]]
    64→///     for k in range(0, 100) step 1 {
    65→///       linalg.matmul {lowering_config = [[4], [4], 1]
    66→///     }
    67→///     // Insert a new loop:
    68→///     for n in range(0, 4 x vscale) step 4 {
    69→///        // Drop a scalable dim:
    70→///        linalg.generic {lowering_config = [4, [4]]
    71→///     }
    72→///   }
    73→/// }
    74→/// ```
    75→///
    76→/// This can now be vectorized and lowered successfully, which produces a
    77→/// dispatch that mixes SME and SVE.
    78→class LLVMCPU2DScalableTo1DScalablePass
    79→    : public impl::LLVMCPU2DScalableTo1DScalablePassBase<
    80→          LLVMCPU2DScalableTo1DScalablePass> {
    81→public:
    82→  using impl::LLVMCPU2DScalableTo1DScalablePassBase<
    83→      LLVMCPU2DScalableTo1DScalablePass>::LLVMCPU2DScalableTo1DScalablePassBase;
    84→  void getDependentDialects(DialectRegistry &registry) const override {
    85→    registry
    86→        .insert<arith::ArithDialect, linalg::LinalgDialect, scf::SCFDialect>();
    87→  }
    88→
    89→  void runOnOperation() override;
    90→};
    91→
    92→static bool opKnownToSupport2DScalableVectorizationWithArmSME(Operation *op) {
    93→  if (auto genericOp = dyn_cast<linalg::GenericOp>(op))
    94→    return isLinalgGeneric2DTranspose(genericOp);
    95→  return isa<linalg::MatmulOp, linalg::MatmulTransposeAOp, linalg::FillOp>(op);
    96→}
    97→
    98→// Note: It would be easy to parameterize this rewrite to convert N-D scalable
    99→// operations to M-D scalable ones (where M < N). However this is currently not
   100→// needed.
   101→static LogicalResult
   102→dropScalabilityFromUnsupportedOperations(mlir::FunctionOpInterface funcOp,
   103→                                         bool assumeArmSME = false) {
   104→  // Note: Which operations should have scalability dropped is specific to
   105→  // ArmSME. The rest of this rewrite could be generic (though currently
   106→  // there's no other targets that support > 1D scalability).
   107→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(funcOp);
   108→  bool isArmSME = assumeArmSME || hasSMEFeature(targetAttr);
   109→
   110→  if (!isArmSME)
   111→    return success();
   112→
   113→  SmallVector<TilingInterface> computeOps;
   114→  funcOp.walk([&](TilingInterface op) {
   115→    if (!opKnownToSupport2DScalableVectorizationWithArmSME(op))
   116→      computeOps.push_back(op);
   117→  });
   118→
   119→  for (TilingInterface tilingOp : computeOps) {
   120→    auto loweringConfigAttr =
   121→        getLoweringConfig<IREE::Codegen::LoweringConfigAttr>(tilingOp);
   122→    if (!loweringConfigAttr)
   123→      continue;
   124→
   125→    TilingConfig tilingConfig(loweringConfigAttr);
   126→    auto [vectorSizes, scalableFlags] = tilingConfig.getVectorTileSizes();
   127→    auto numScalableDims = llvm::count(scalableFlags, true);
   128→
   129→    if (numScalableDims <= 1)
   130→      continue;
   131→
   132→    SmallVector<int64_t> loopTileSizes;
   133→    SmallVector<bool> newScalableFlags;
   134→    for (auto [flag, size] : llvm::zip_equal(scalableFlags, vectorSizes)) {
   135→      if (flag && numScalableDims >= 2) {
   136→        --numScalableDims;
   137→        loopTileSizes.push_back(size);
   138→        newScalableFlags.push_back(false);
   139→      } else {
   140→        loopTileSizes.push_back(0);
   141→        newScalableFlags.push_back(flag);
   142→      }
   143→    }
   144→
   145→    IRRewriter rewriter(tilingOp->getContext());
   146→    rewriter.setInsertionPoint(tilingOp);
   147→
   148→    // 2. Re-tile the operation with some scalability dropped. This introduces
   149→    // loops for previously scalable vector/tile sizes.
   150→    scf::SCFTilingOptions options;
   151→    setSCFTileSizes(options, tilingOp, loopTileSizes, /*tileScalableFlags=*/{});
   152→    auto tilingResult = scf::tileUsingSCF(rewriter, tilingOp, options);
   153→    if (failed(tilingResult))
   154→      return failure();
   155→
   156→    // 3. Update the lowering config of the new tiled operations.
   157→    auto newLoweringConfig = tilingConfig.getLoweringConfigWithNewVectorSizes(
   158→        vectorSizes, newScalableFlags);
   159→    for (auto *newOp : tilingResult->tiledOps) {
   160→      if (isa<TilingInterface>(newOp))
   161→        setLoweringConfig(newOp, newLoweringConfig);
   162→    }
   163→
   164→    rewriter.replaceOp(tilingOp, tilingResult->mergeResult.replacements);
   165→  }
   166→  return success();
   167→}
   168→
   169→void LLVMCPU2DScalableTo1DScalablePass::runOnOperation() {
   170→  if (failed(dropScalabilityFromUnsupportedOperations(getOperation(),
   171→                                                      assumeArmSME)))
   172→    signalPassFailure();
   173→}
   174→
   175→} // namespace
   176→} // namespace mlir::iree_compiler
