    31→namespace {
    32→
    33→// Returns true if `contractionOp` is of the form
    34→//   matrix * transposed_matrix.
    35→// That is, if there are 2 parallel iterators, say M and N, 1 additive reduction
    36→// iterator, say K, and the indexing maps are {{M, K}, {N, K}, {M, N}}.
    37→static bool isMatrixTimesMatrixTransposed(vector::ContractionOp contractionOp) {
    38→  // Check that the reduction is additive.
    39→  if (contractionOp.getKind() != vector::CombiningKind::ADD) {
    40→    return false;
    41→  }
    42→  // Check that there are 2 parallel and 1 reduction iterators.
    43→  auto iteratorTypes = contractionOp.getIteratorTypes().getValue();
    44→  if (iteratorTypes.size() != 3) {
    45→    return false;
    46→  }
    47→  SmallVector<int, 3> parallelIterators;
    48→  SmallVector<int, 3> reductionIterators;
    49→  for (int i = 0; i < 3; i++) {
    50→    if (vector::isParallelIterator(iteratorTypes[i])) {
    51→      parallelIterators.push_back(i);
    52→    } else if (vector::isReductionIterator(iteratorTypes[i])) {
    53→      reductionIterators.push_back(i);
    54→    } else {
    55→      return false;
    56→    }
    57→  }
    58→  if (parallelIterators.size() != 2 || reductionIterators.size() != 1) {
    59→    return false;
    60→  }
    61→  // Give the found iterators some idiomatic names.
    62→  const int MIter = parallelIterators[0];
    63→  const int NIter = parallelIterators[1];
    64→  const int KIter = reductionIterators[0];
    65→  // Check that there are 3 indexing maps.
    66→  auto indexingMaps = contractionOp.getIndexingMapsArray();
    67→  if (indexingMaps.size() != 3) {
    68→    return false;
    69→  }
    70→  // Check that the indexing maps have the expected form.
    71→  const int expectedMapResults[3][2] = {
    72→      {MIter, KIter}, {NIter, KIter}, {MIter, NIter}};
    73→  for (int m = 0; m < 3; ++m) {
    74→    auto map = indexingMaps[m];
    75→    if (map.getNumDims() != 3 || map.getNumResults() != 2) {
    76→      return false;
    77→    }
    78→    for (int r = 0; r < 2; ++r) {
    79→      int actualMapResult =
    80→          cast<AffineDimExpr>(map.getResults()[r]).getPosition();
    81→      if (actualMapResult != expectedMapResults[m][r]) {
    82→        return false;
    83→      }
    84→    }
    85→  }
    86→  return true;
    87→}
    88→
    89→// Returns true if `contractionOp` is of the form
    90→//   matrix * transposed_matrix
    91→// where matrix is a vector<{mSize}x{kSize}xType>, and
    92→// transposed_matrix is a vector<{nSize}x{kSize}xType>.
    93→//
    94→// Also returns true if the above condition is met after swapping
    95→// mSize<->nSize and one of these two values is 1, and `transpose` is not null.
    96→// In that case, the output-param `*transpose` is set to true. Rationale: we
    97→// want to use the same kernel for vector*matrix and matrix*vector. The good
    98→// thing with MMT, namely
    99→//
   100→//    A * Transpose(B)
   101→//
   102→// is that swapping A and B merely transposes the result:
   103→//
   104→//    B * Transpose(A) = Transpose( A * Transpose(B) )
   105→//
   106→// This opens the possibility of reducing vector*matrix to matrix*vector
   107→// by merely swappign LHS<->RHS. Why is this specific to the case where one of
   108→// the sides is a vector? Because transposing the result is not OK in general,
   109→// we don't want to write out the result accumulators in the wrong storage
   110→// order. However, when one of the two sides is a vector, so is the result
   111→// accumulator, and for a vector shape (i.e. Mx1 or 1xN), storage orders do not
   112→// matter.
   113→static bool matchMMT(vector::ContractionOp contractionOp, int64_t mSize,
   114→                     int64_t kSize, int64_t nSize, bool *transpose = nullptr) {
   115→  if (!isMatrixTimesMatrixTransposed(contractionOp)) {
   116→    return false;
   117→  }
   118→  VectorType lhsType = llvm::cast<VectorType>(contractionOp.getLhs().getType());
   119→  VectorType rhsType = llvm::cast<VectorType>(contractionOp.getRhs().getType());
   120→  auto lhsShape = lhsType.getShape();
   121→  auto rhsShape = rhsType.getShape();
   122→  if (lhsShape[1] != kSize || rhsShape[1] != kSize) {
   123→    return false;
   124→  }
   125→  if (lhsShape[0] == mSize && rhsShape[0] == nSize) {
   126→    return true;
   127→  }
   128→  if (lhsShape[0] == nSize && rhsShape[0] == mSize && transpose != nullptr) {
   129→    *transpose = true;
   130→    return true;
   131→  }
   132→  return false;
   133→}
   134→
   135→// `promotedResult` is required to be a Vector.
   136→// If its VectorType does not have `promotedType` as its element type, or
   137→// the operand to the type-promotion op is not `unpromotedType` returns a null
   138→// Value.
   139→// If `unpromotedType == promotedType`, return `promotedResult` unchanged.
   140→// Otherwise, checks that `promotedResult` is defined by a type-promotion op
   141→// (such as arith::ExtSIOp) promoting from `unpromotedType` to `promotedType`,
   142→// and returns the input of that promotion op.
   143→// Note that this only looks at the immediately defining operation, so we likely
   144→// want to have earlier passes that sink widening operations as far down as
   145→// possible, which is probably just good regardless.
   146→static Value getUnpromotedInput(Type unpromotedType, Type promotedType,
   147→                                Value promotedResult) {
   148→  VectorType promotedResultVectorType =
   149→      llvm::cast<VectorType>(promotedResult.getType());
   150→  if (promotedResultVectorType.getElementType() != promotedType) {
   151→    return nullptr;
   152→  }
   153→  if (unpromotedType == promotedType) {
   154→    return promotedResult;
   155→  }
   156→  // TODO: handle promotion of floating point types. Not doing it for now as
   157→  // it wouldn't be exercised.
   158→  auto extSIOp = promotedResult.getDefiningOp<arith::ExtSIOp>();
   159→  if (!extSIOp) {
   160→    return nullptr;
   161→  }
   162→  Value extInput = extSIOp.getIn();
   163→  if (llvm::cast<VectorType>(extInput.getType()).getElementType() !=
   164→      unpromotedType) {
   165→    return nullptr;
   166→  }
   167→  return extInput;
   168→}
   169→
   170→// Helper to create a 1D, contiguous slice of a 1D vector.
   171→static Value extract1DSlice(PatternRewriter &rewriter, Location loc,
   172→                            VectorType dstVecType, Value input, int position) {
   173→  assert(cast<VectorType>(input.getType()).getRank() == 1);
   174→  assert(dstVecType.getRank() == 1);
   175→  std::array<int64_t, 1> offsets{position};
   176→  std::array<int64_t, 1> strides{1};
   177→  return rewriter.create<vector::ExtractStridedSliceOp>(
   178→      loc, input, offsets, dstVecType.getShape(), strides);
   179→}
   180→
   181→// Helper to extract an element of a 1D vector.
   182→static Value extract(PatternRewriter &rewriter, Location loc, Value input,
   183→                     int position) {
   184→  VectorType vectorType = llvm::cast<VectorType>(input.getType());
   185→  assert(vectorType.getRank() == 1);
   186→  (void)vectorType;
   187→  std::array<int64_t, 1> offsets{position};
   188→  return rewriter.create<vector::ExtractOp>(loc, input, offsets);
   189→}
   190→
   191→// Helper to flatten a N-dimensional vector to a 1D vector.
   192→static Value flatten(PatternRewriter &rewriter, Location loc, Value vector) {
   193→  VectorType inputVecType = llvm::cast<VectorType>(vector.getType());
   194→  VectorType dstType = VectorType::get(inputVecType.getNumElements(),
   195→                                       inputVecType.getElementType());
   196→  return rewriter.create<vector::ShapeCastOp>(loc, dstType, vector);
   197→}
