   199→// Describes a kernel. This struct is kept small to separate the kernels
   200→// themselves from the MLIR-specific generators consuming them
   201→// (see MMTKernelGenerator).
   202→//
   203→// There is some redundancy among this struct's fields: see the relationships
   204→// between fields that are enforced in validate(). This redundancy helps:
   205→// (1) Avoid having to perform divisions (performance concern, and readability
   206→//         concern as would care for these divisions to be exact).
   207→// (2) Be explicit about the size of the vectors involved in the kernel's
   208→//         "calling convention".
   209→struct MMTKernel {
   210→  enum class ScalarType : int8_t { None, I8, I32, F32 };
   211→  // Element type of the LHS vectors.
   212→  ScalarType lhsType = ScalarType::None;
   213→  // Element type of the RHS vectors.
   214→  ScalarType rhsType = ScalarType::None;
   215→  // Element type of the Accumulator and output vectors.
   216→  ScalarType accType = ScalarType::None;
   217→  // Number of rows of the LHS and Accumulator tile.
   218→  int8_t m0 = 0;
   219→  // Reduction dimension, i.e. number of columns of the LHS.
   220→  int8_t k0 = 0;
   221→  // Number of rows of the RHS (note that the operation being targeted, MMT,
   222→  // is matrix multiplication with a *transposed* RHS)
   223→  int8_t n0 = 0;
   224→  // Number of LHS elements in the type of register to be used for the LHS.
   225→  // This is > 1 if SIMD registers are to be used.
   226→  // Note: LHS/RHS/Accumulator may use registers of different sizes.
   227→  int8_t lhsRegSize = 0;
   228→  // Number of RHS elements fitting in the type of register to be used for RHS.
   229→  int8_t rhsRegSize = 0;
   230→  // Number of Accumulator elements fitting  in the type of register to be used
   231→  // for the accumulator.
   232→  int8_t accRegSize = 0;
   233→  // Number of registers needed to hold the LHS.
   234→  int8_t lhsRegs = 0;
   235→  // Number of registers needed to hold the RHS.
   236→  int8_t rhsRegs = 0;
   237→  // Number of registers needed to hold the Accumulator.
   238→  int8_t accRegs = 0;
   239→  // If not null, points to the inline asm code template for this kernel.
   240→  // Register operands for the LHS, RHS and Accumulator are to be referenced as
   241→  // $(lhs:<i>), $(rhs:<i>), $(acc:<i>) respectively, where i is a decimal
   242→  // integer specifying the i-th register for each case (numbered independently,
   243→  // so each starts at 0).
   244→  const char *asmImpl = nullptr;
   245→  // If not null, points to the clobbers list, i.e. the list of registers
   246→  // that the compiler will reserve for this inline asm block's use, in addition
   247→  // to the ones implicitly allocated for the declared inputs and outputs. Using
   248→  // C inline_asm syntax: comma-separated list of raw register names e.g.
   249→  // "v14,v15"
   250→  const char *asmClobbers = nullptr;
   251→
   252→  void validate() const {
   253→    assert(m0 * k0 == lhsRegSize * lhsRegs); // number of elements of LHS
   254→    assert(n0 * k0 == rhsRegSize * rhsRegs); // number of elements of RHS
   255→    assert(m0 * n0 == accRegSize * accRegs); // number of elements of Accum
   256→    assert(lhsType != ScalarType::None);
   257→    assert(rhsType != ScalarType::None);
   258→    assert(accType != ScalarType::None);
   259→  }
   260→};
   261→
   262→// i8*i8->i32 kernel for Aarch64 NEON.
   263→//
   264→// Historically certain such kernels [1] required int8 inputs not have the
   265→// value -128, which enabled a different kernel design taking advantage
   266→// of the narrow range to accumulate once within int16 accumulators without
   267→// overflow. These kernels were a 1.5x speedup on some late-2010s out-of-order
   268→// cores (ARM Cortex A57/A72/A73, Apple A6--A12, Samsung Exynos M3), but became
   269→// obsolete with the +dotprod feature (ARM Cortex-A76, Apple A13), and never
   270→// were useful on in-order ARM Cortex-A53/A55. So going forward, they are not
   271→// anymore a useful trade-off even in frameworks (such as TensorFlow Lite) that
   272→// are designed to avoid -128 values. There is a large ecosystem cost in
   273→// maintaining that restriction, and it wouldn't make sense to introduce it now
   274→// in new frameworks such as MLIR or IREE, so the present kernel is general,
   275→// supports arbitrary int8 values and does not try to use such optimizations.
   276→//
   277→// This kernel is needed because: at the moment, the codegen has multiple
   278→// issues. It uses inefficient scalar memory access instructions,
   279→// expands int8 values to int32, and performs slow int32*int32 multiplications:
   280→//   118d8: f0 12 c0 39   ldrsb w16, [x23, #4]
   281→//   ...
   282→//   118f4: 1b 0e 04 4e   dup v27.4s, w16
   283→//   ...
   284→//   11900: 32 97 bb 4e   mla v18.4s, v25.4s, v27.4s
   285→//   11904: 57 97 bb 4e   mla v23.4s, v26.4s, v27.4s
   286→//
   287→//
   288→// [1]:
   289→// https://github.com/google/ruy/blob/2d950b3bfa7ebfbe7a97ecb44b1cc4da5ac1d6f0/ruy/kernel_arm64.cc#L93
   290→MMTKernel MMTKernel_8x1x8_i8i8i32_Aarch64_Baseline_InlineAsm() {
   291→  MMTKernel kernel;
   292→  kernel.lhsType = MMTKernel::ScalarType::I8;
   293→  kernel.rhsType = MMTKernel::ScalarType::I8;
   294→  kernel.accType = MMTKernel::ScalarType::I32;
   295→  kernel.m0 = 8; // shape: 8x1x8, outer-product.
   296→  kernel.k0 = 1; // note: we would have enough registers to widen to 12x1x8
   297→  kernel.n0 = 8; // if needed.
   298→  kernel.lhsRegSize = 8; // LHS NEON register type: int8x8
   299→  kernel.rhsRegSize = 8; // RHS NEON register type: int8x8
   300→  kernel.accRegSize = 4; // Accum NEON register type: int32x4
   301→  kernel.lhsRegs = 1;
   302→  kernel.rhsRegs = 1;
   303→  kernel.accRegs = 16; // = 8*8/4 for 8x8 accumulators, 4 per register
   304→  kernel.asmImpl = R"ASM(
   305→      // NEON does not have instructions to multiply int8 values and accumulate
   306→      // into int32. This kernel sign-extends int8 to int16, then uses
   307→      // smlal[2] to multiply-accumulate int16 values into int32 accumulators.
   308→      sxtl v14.8h, $(lhs:0).8b  // v14.8h = sign-extend LHS int8 to int16
   309→      sxtl v15.8h, $(rhs:0).8b  // v15.8h = sign-extend RHS int8 to int16
   310→      smlal $(acc:0).4s, v15.4h, v14.h[0]
   311→      smlal2 $(acc:1).4s, v15.8h, v14.h[0]
   312→      smlal $(acc:2).4s, v15.4h, v14.h[1]
   313→      smlal2 $(acc:3).4s, v15.8h, v14.h[1]
   314→      smlal $(acc:4).4s, v15.4h, v14.h[2]
   315→      smlal2 $(acc:5).4s, v15.8h, v14.h[2]
   316→      smlal $(acc:6).4s, v15.4h, v14.h[3]
   317→      smlal2 $(acc:7).4s, v15.8h, v14.h[3]
   318→      smlal $(acc:8).4s, v15.4h, v14.h[4]
   319→      smlal2 $(acc:9).4s, v15.8h, v14.h[4]
   320→      smlal $(acc:10).4s, v15.4h, v14.h[5]
   321→      smlal2 $(acc:11).4s, v15.8h, v14.h[5]
   322→      smlal $(acc:12).4s, v15.4h, v14.h[6]
   323→      smlal2 $(acc:13).4s, v15.8h, v14.h[6]
   324→      smlal $(acc:14).4s, v15.4h, v14.h[7]
   325→      smlal2 $(acc:15).4s, v15.8h, v14.h[7]
   326→    )ASM";
   327→  kernel.asmClobbers = "v14,v15";
   328→  return kernel;
   329→}
   330→
   331→// i8*i8->i32 kernel for Aarch64 NEON, matrix*vector
   332→//
   333→// This kernel is needed because: at the moment, the codegen is generating
   334→// 177 instructions for this kernel (not peeled).
   335→MMTKernel MMTKernel_8x8x1_i8i8i32_Aarch64_Baseline_InlineAsm() {
   336→  MMTKernel kernel;
   337→  kernel.lhsType = MMTKernel::ScalarType::I8;
   338→  kernel.rhsType = MMTKernel::ScalarType::I8;
   339→  kernel.accType = MMTKernel::ScalarType::I32;
   340→  kernel.m0 = 8; // shape: 8x8x1, matrix*vector
   341→  kernel.k0 = 8;
   342→  kernel.n0 = 1;
   343→  kernel.lhsRegSize = 16; // LHS NEON register type: int8x16
   344→  kernel.rhsRegSize = 8;  // RHS NEON register type: int8x8
   345→  kernel.accRegSize = 4;  // Accum NEON register type: int32x4
   346→  kernel.lhsRegs = 4;     // = 8x8/16 for 8x8 LHS elems, 16 per register
   347→  kernel.rhsRegs = 1;
   348→  kernel.accRegs = 2; // = 8/4 for 8 accumulators, 4 per register
   349→  kernel.asmImpl = R"ASM(
   350→    // This kernel multiplies int8 values into temporary int16 values in
   351→    // registers v8--v15, then performs additions. We can't use
   352→    // multiply-accumulate instructions here because of the lack of an
   353→    // instruction multiplying int8 values and accumulating into int32, and
   354→    // we prefer to avoid the overhead of sign-extending the inputs from int8
   355→    // to int16 in this matrix*vector kernel where the largest matrix is the
   356→    // LHS.
   357→    ins v15.d[1], $(rhs:0).d[0]  // copy 1st half of $(rhs:0) to 2nd half of v15
   358→    smull v8.8h, $(lhs:0).8b, $(rhs:0).8b
   359→    smull2 v9.8h, $(lhs:0).16b, v15.16b
   360→    smull v10.8h, $(lhs:1).8b, $(rhs:0).8b
   361→    smull2 v11.8h, $(lhs:1).16b, v15.16b
   362→    smull v12.8h, $(lhs:2).8b, $(rhs:0).8b
   363→    smull2 v13.8h, $(lhs:2).16b, v15.16b
   364→    smull v14.8h, $(lhs:3).8b, $(rhs:0).8b
   365→    smull2 v15.8h, $(lhs:3).16b, v15.16b
   366→    // Now if we were able to codegen not just this MMT in isolation but
   367→    // a whole loop, we would diverge at this point: instead of doing the full
   368→    // additive reduction that the instructions below do, we would do only
   369→    // minimal reductions to temporary int32 accumulators
   370→    // (e.g. sadalp tmp.4s, v8.8h) and we would defer the rest of the work
   371→    // to the end of the loop. This is an example of how "MMT vector.contract"
   372→    // is not a perfect abstraction for "basic block of a MMT inner loop".
   373→    // Anyway...
   374→    //
   375→    // pairwise additions of int16 lanes to int32.
   376→    // So each result int32 is the sum of 2 products.
   377→    saddlp v8.4s, v8.8h
   378→    saddlp v9.4s, v9.8h
   379→    saddlp v10.4s, v10.8h
   380→    saddlp v11.4s, v11.8h
   381→    saddlp v12.4s, v12.8h
   382→    saddlp v13.4s, v13.8h
   383→    saddlp v14.4s, v14.8h
   384→    saddlp v15.4s, v15.8h
   385→    // pairwise additions of int32s, so each result is the sum of 4 products.
   386→    addp v8.4s, v8.4s, v9.4s
   387→    addp v10.4s, v10.4s, v11.4s
   388→    addp v12.4s, v12.4s, v13.4s
   389→    addp v14.4s, v14.4s, v15.4s
   390→    // pairwise additions of int32s, so each result is the sum of 8 products.
   391→    addp v8.4s, v8.4s, v10.4s
   392→    addp v12.4s, v12.4s, v14.4s
   393→    // Add to destination accumulators
   394→    add $(acc:0).4s, $(acc:0).4s, v8.4s
   395→    add $(acc:1).4s, $(acc:1).4s, v12.4s
   396→    )ASM";
   397→  kernel.asmClobbers = "v8,v9,v10,v11,v12,v13,v14,v15";
   398→  return kernel;
   399→}
