   401→// i8*i8->i32 kernel for Aarch64 NEON +dotprod
   402→//
   403→// This kernel is needed because: at the moment, codegen doesn't know how to
   404→// make use of dotprod instructions.
   405→MMTKernel MMTKernel_8x4x8_i8i8i32_Aarch64Dotprod_InlineAsm() {
   406→  MMTKernel kernel;
   407→  kernel.lhsType = MMTKernel::ScalarType::I8;
   408→  kernel.rhsType = MMTKernel::ScalarType::I8;
   409→  kernel.accType = MMTKernel::ScalarType::I32;
   410→  kernel.m0 = 8; // shape: 8x4x8. We would have enough registers to widen this
   411→  kernel.k0 = 4; // to 12x4x8 if needed.
   412→  kernel.n0 = 8;
   413→  kernel.lhsRegSize = 16; // LHS NEON register type: int8x16
   414→  kernel.rhsRegSize = 16; // RHS NEON register type: int8x16
   415→  kernel.accRegSize = 4;  // Accum NEON register type: int32x4
   416→  kernel.lhsRegs = 2;     // = 8x4/16 for 8x4 LHS elems, 16 per register
   417→  kernel.rhsRegs = 2;     // = 8x4/16 for 8x4 RHS elems, 16 per register
   418→  kernel.accRegs = 16;    // = 8x8/4 for 8x8 Accum elems, 4 per register
   419→  kernel.asmImpl = R"ASM(
   420→      // Note on the operands ordering: RHS before LHS, because we want
   421→      // to multiply a 4x4 tile from RHS against a row-vector from LHS to
   422→      // produce a row-vector of Accumulators, because the accumulator
   423→      // needs to be row-major.
   424→      sdot $(acc:0).4s, $(rhs:0).16b, $(lhs:0).4b[0]
   425→      sdot $(acc:1).4s, $(rhs:1).16b, $(lhs:0).4b[0]
   426→      sdot $(acc:2).4s, $(rhs:0).16b, $(lhs:0).4b[1]
   427→      sdot $(acc:3).4s, $(rhs:1).16b, $(lhs:0).4b[1]
   428→      sdot $(acc:4).4s, $(rhs:0).16b, $(lhs:0).4b[2]
   429→      sdot $(acc:5).4s, $(rhs:1).16b, $(lhs:0).4b[2]
   430→      sdot $(acc:6).4s, $(rhs:0).16b, $(lhs:0).4b[3]
   431→      sdot $(acc:7).4s, $(rhs:1).16b, $(lhs:0).4b[3]
   432→      sdot $(acc:8).4s, $(rhs:0).16b, $(lhs:1).4b[0]
   433→      sdot $(acc:9).4s, $(rhs:1).16b, $(lhs:1).4b[0]
   434→      sdot $(acc:10).4s, $(rhs:0).16b, $(lhs:1).4b[1]
   435→      sdot $(acc:11).4s, $(rhs:1).16b, $(lhs:1).4b[1]
   436→      sdot $(acc:12).4s, $(rhs:0).16b, $(lhs:1).4b[2]
   437→      sdot $(acc:13).4s, $(rhs:1).16b, $(lhs:1).4b[2]
   438→      sdot $(acc:14).4s, $(rhs:0).16b, $(lhs:1).4b[3]
   439→      sdot $(acc:15).4s, $(rhs:1).16b, $(lhs:1).4b[3]
   440→    )ASM";
   441→  return kernel;
   442→}
