   444→// i8*i8->i32 kernel for Aarch64 NEON +dotprod, matrix*vector
   445→//
   446→// This kernel is needed because: at the moment, codegen doesn't know how to
   447→// make use of dotprod instructions.
   448→MMTKernel MMTKernel_8x4x1_i8i8i32_Aarch64Dotprod_InlineAsm() {
   449→  MMTKernel kernel;
   450→  kernel.lhsType = MMTKernel::ScalarType::I8;
   451→  kernel.rhsType = MMTKernel::ScalarType::I8;
   452→  kernel.accType = MMTKernel::ScalarType::I32;
   453→  kernel.m0 = 8; // shape: 8x4x1.
   454→  kernel.k0 = 4;
   455→  kernel.n0 = 1;
   456→  kernel.lhsRegSize = 16; // LHS NEON register type: int8x16
   457→  kernel.rhsRegSize = 4;  // RHS NEON register type: int8x4. This is very small
   458→                          // and forces sub-optimal codegen. This needs to be
   459→                          // widened by peeling the surrounding loop, not by
   460→                          // increasing the k0 of this MMT, which would change
   461→                          // the data layout in an unwanted way.
   462→  kernel.accRegSize = 4;  // LHS NEON register type: int8x16
   463→  kernel.lhsRegs = 2;     // = 8x4/16 for 8x4 LHS elems, 16 per register
   464→  kernel.rhsRegs = 1;     // = 4/4 for 4 LHS elems, 4 per register
   465→  kernel.accRegs = 2;     // = 8/4 for 8 Accum elems, 4 per register
   466→  kernel.asmImpl = R"ASM(
   467→      sdot $(acc:0).4s, $(lhs:0).16b, $(rhs:0).4b[0]
   468→      sdot $(acc:1).4s, $(lhs:1).16b, $(rhs:0).4b[0]
   469→    )ASM";
   470→  return kernel;
   471→}
   472→
   473→// i8*i8->i32 kernel for Aarch64 NEON +i8mm
   474→//
   475→// This kernel is needed because: at the moment, codegen doesn't know how to
   476→// make use of i8mm instructions.
   477→MMTKernel MMTKernel_8x8x8_i8i8i32_Aarch64I8mm_InlineAsm() {
   478→  MMTKernel kernel;
   479→  kernel.lhsType = MMTKernel::ScalarType::I8;
   480→  kernel.rhsType = MMTKernel::ScalarType::I8;
   481→  kernel.accType = MMTKernel::ScalarType::I32;
   482→  kernel.m0 = 8; // shape: 8x8x8. We would have enough registers to widen this
   483→  kernel.k0 = 8; // to 12x8x8 if needed.
   484→  kernel.n0 = 8;
   485→  kernel.lhsRegSize = 16; // LHS NEON register type: int8x16
   486→  kernel.rhsRegSize = 16; // RHS NEON register type: int8x16
   487→  kernel.accRegSize = 4;  // Accum NEON register type: int32x4
   488→  kernel.lhsRegs = 4;     // = 8x8/16 for 8x4 LHS elems, 16 per register
   489→  kernel.rhsRegs = 4;     // = 8x8/16 for 8x4 RHS elems, 16 per register
   490→  kernel.accRegs = 16;    // = 8x8/4 for 8x8 Accum elems, 4 per register
   491→  kernel.asmImpl = R"ASM(
   492→      // What's with the horrendous shuffles (zip, uzp instructions) ?
   493→      // The smmla instruction works with a 2x2 accumulator tile.
   494→      // So at the moment, given the MMT vector.contract representation of
   495→      // the basic block, we have to perform this re-tiling to 2x2 tiles.
   496→      //
   497→      // This is not really optimized -- just provided to help shape the next
   498→      // stage of the discussion, which will be how we change the abstractions
   499→      // to resolve this.
   500→      //
   501→      // For instance, if we compiled a whole loop at once, we would only need
   502→      // to do so at the start and at the end of the loop. Or even without
   503→      // handing the whole loop to asm, we could make the vector.contract
   504→      // higher-dimensional to allow representing this nested tiled layout.
   505→      // One thing that we should keep in mind though is that this unusual
   506→      // 2x2 tiled layout is specific to matrix multiplication instructions.
   507→      // If the matmul kernel were fused into consumer ops, those would probably
   508→      // prefer not to deal with a 2x2 tiled layout.
   509→      //
   510→      // We also can't easily generalize from this to what will be ARMv9+SME.
   511→      // There, the matmul instruction will also produce a 2D matrix tile,
   512→      // but that will be much wider, 16x16, and itself row-major, so that when
   513→      // store it back to NEON/SVE registers, each of those will be contained
   514→      // within one row. Even if we put multiple such 16x16 tiles side-by-side
   515→      // in the overall kernel, that will still be at a scale larger than
   516→      // individual NEON/SVE registers.
   517→      //
   518→      // Rows 0-1 of the 8x8 accumulator tile
   519→      zip1 v28.2d, $(acc:0).2d, $(acc:2).2d
   520→      zip2 v29.2d, $(acc:0).2d, $(acc:2).2d
   521→      zip1 v30.2d, $(acc:1).2d, $(acc:3).2d
   522→      zip2 v31.2d, $(acc:1).2d, $(acc:3).2d
   523→      smmla v28.4s, $(lhs:0).16b, $(rhs:0).16b
   524→      smmla v29.4s, $(lhs:0).16b, $(rhs:1).16b
   525→      smmla v30.4s, $(lhs:0).16b, $(rhs:2).16b
   526→      smmla v31.4s, $(lhs:0).16b, $(rhs:3).16b
   527→      uzp1 $(acc:0).2d, v28.2d, v29.2d
   528→      uzp1 $(acc:1).2d, v30.2d, v31.2d
   529→      uzp2 $(acc:2).2d, v28.2d, v29.2d
   530→      uzp2 $(acc:3).2d, v30.2d, v31.2d
   531→      // Rows 2-3 of the 8x8 accumulator tile
   532→      zip1 v28.2d, $(acc:4).2d, $(acc:6).2d
   533→      zip2 v29.2d, $(acc:4).2d, $(acc:6).2d
   534→      zip1 v30.2d, $(acc:5).2d, $(acc:7).2d
   535→      zip2 v31.2d, $(acc:5).2d, $(acc:7).2d
   536→      smmla v28.4s, $(lhs:1).16b, $(rhs:0).16b
   537→      smmla v29.4s, $(lhs:1).16b, $(rhs:1).16b
   538→      smmla v30.4s, $(lhs:1).16b, $(rhs:2).16b
   539→      smmla v31.4s, $(lhs:1).16b, $(rhs:3).16b
   540→      uzp1 $(acc:4).2d, v28.2d, v29.2d
   541→      uzp1 $(acc:5).2d, v30.2d, v31.2d
   542→      uzp2 $(acc:6).2d, v28.2d, v29.2d
   543→      uzp2 $(acc:7).2d, v30.2d, v31.2d
   544→      // Rows 4-5 of the 8x8 accumulator tile
   545→      zip1 v28.2d, $(acc:8).2d, $(acc:10).2d
   546→      zip2 v29.2d, $(acc:8).2d, $(acc:10).2d
   547→      zip1 v30.2d, $(acc:9).2d, $(acc:11).2d
   548→      zip2 v31.2d, $(acc:9).2d, $(acc:11).2d
   549→      smmla v28.4s, $(lhs:2).16b, $(rhs:0).16b
   550→      smmla v29.4s, $(lhs:2).16b, $(rhs:1).16b
   551→      smmla v30.4s, $(lhs:2).16b, $(rhs:2).16b
   552→      smmla v31.4s, $(lhs:2).16b, $(rhs:3).16b
   553→      uzp1 $(acc:8).2d, v28.2d, v29.2d
   554→      uzp1 $(acc:9).2d, v30.2d, v31.2d
   555→      uzp2 $(acc:10).2d, v28.2d, v29.2d
   556→      uzp2 $(acc:11).2d, v30.2d, v31.2d
   557→      // Rows 6-7 of the 8x8 accumulator tile
   558→      zip1 v28.2d, $(acc:12).2d, $(acc:14).2d
   559→      zip2 v29.2d, $(acc:12).2d, $(acc:14).2d
   560→      zip1 v30.2d, $(acc:13).2d, $(acc:15).2d
   561→      zip2 v31.2d, $(acc:13).2d, $(acc:15).2d
   562→      smmla v28.4s, $(lhs:3).16b, $(rhs:0).16b
   563→      smmla v29.4s, $(lhs:3).16b, $(rhs:1).16b
   564→      smmla v30.4s, $(lhs:3).16b, $(rhs:2).16b
   565→      smmla v31.4s, $(lhs:3).16b, $(rhs:3).16b
   566→      uzp1 $(acc:12).2d, v28.2d, v29.2d
   567→      uzp1 $(acc:13).2d, v30.2d, v31.2d
   568→      uzp2 $(acc:14).2d, v28.2d, v29.2d
   569→      uzp2 $(acc:15).2d, v30.2d, v31.2d
   570→    )ASM";
   571→  kernel.asmClobbers = "v28,v29,v30,v31";
   572→  return kernel;
   573→}
