   587→// f32*f32->f32 kernel for Aarch64 NEON
   588→//
   589→// Note: this asm kernel isn't needed. The default vector.contract
   590→// lowerings already result in essentially the same code. This is included for
   591→// now for completeness, as we need the f32 matrix*vector kernel below anyway.
   592→MMTKernel MMTKernel_8x1x8_f32f32f32_Aarch64_Baseline_InlineAsm() {
   593→  MMTKernel kernel;
   594→  kernel.lhsType = MMTKernel::ScalarType::F32;
   595→  kernel.rhsType = MMTKernel::ScalarType::F32;
   596→  kernel.accType = MMTKernel::ScalarType::F32;
   597→  kernel.m0 = 8;
   598→  kernel.k0 = 1;
   599→  kernel.n0 = 8;
   600→  kernel.lhsRegSize = 4;
   601→  kernel.rhsRegSize = 4;
   602→  kernel.accRegSize = 4;
   603→  kernel.lhsRegs = 2;
   604→  kernel.rhsRegs = 2;
   605→  kernel.accRegs = 16;
   606→  kernel.asmImpl = R"ASM(
   607→      fmla $(acc:0).4s, $(rhs:0).4s, $(lhs:0).s[0]
   608→      fmla $(acc:1).4s, $(rhs:1).4s, $(lhs:0).s[0]
   609→      fmla $(acc:2).4s, $(rhs:0).4s, $(lhs:0).s[1]
   610→      fmla $(acc:3).4s, $(rhs:1).4s, $(lhs:0).s[1]
   611→      fmla $(acc:4).4s, $(rhs:0).4s, $(lhs:0).s[2]
   612→      fmla $(acc:5).4s, $(rhs:1).4s, $(lhs:0).s[2]
   613→      fmla $(acc:6).4s, $(rhs:0).4s, $(lhs:0).s[3]
   614→      fmla $(acc:7).4s, $(rhs:1).4s, $(lhs:0).s[3]
   615→      fmla $(acc:8).4s, $(rhs:0).4s, $(lhs:1).s[0]
   616→      fmla $(acc:9).4s, $(rhs:1).4s, $(lhs:1).s[0]
   617→      fmla $(acc:10).4s, $(rhs:0).4s, $(lhs:1).s[1]
   618→      fmla $(acc:11).4s, $(rhs:1).4s, $(lhs:1).s[1]
   619→      fmla $(acc:12).4s, $(rhs:0).4s, $(lhs:1).s[2]
   620→      fmla $(acc:13).4s, $(rhs:1).4s, $(lhs:1).s[2]
   621→      fmla $(acc:14).4s, $(rhs:0).4s, $(lhs:1).s[3]
   622→      fmla $(acc:15).4s, $(rhs:1).4s, $(lhs:1).s[3]
   623→    )ASM";
   624→  return kernel;
   625→}
