   627→// f32*f32->f32 kernel for Aarch64 NEON, matrix*vector
   628→//
   629→// Note: this is about the most naive possible SIMD kernel here, and it should
   630→// not be needed as this should be an easy case for codegen. Here we are very
   631→// limited in what we can do as a MMT vector.contract lowering - to make a
   632→// better kernel, we would need to peel the surrounding loop, and implement
   633→// a larger vector.contract with an additional parallel iterator, accumulating
   634→// into more separate registers, deferring reduction to the end of the loop.
   635→//
   636→// And yet, this kernel is currently needed, because at the moment this is what
   637→// the codegen generates:
   638→//   10d08: 90 44 c1 ac   ldp     q16, q17, [x4], #32
   639→//   10d0c: c6 04 00 f1   subs    x6, x6, #1
   640→//   10d10: 13 42 10 6e   ext     v19.16b, v16.16b, v16.16b, #8
   641→//   10d14: 34 42 11 6e   ext     v20.16b, v17.16b, v17.16b, #8
   642→//   10d18: b2 44 40 bc   ldr     s18, [x5], #4
   643→//   10d1c: 40 ce 30 0e   fmla    v0.2s, v18.2s, v16.2s
   644→//   10d20: 47 12 b0 0f   fmla    v7.2s, v18.2s, v16.s[1]
   645→//   10d24: 46 1a b0 0f   fmla    v6.2s, v18.2s, v16.s[3]
   646→//   10d28: 42 ce 31 0e   fmla    v2.2s, v18.2s, v17.2s
   647→//   10d2c: 41 12 b1 0f   fmla    v1.2s, v18.2s, v17.s[1]
   648→//   10d30: 45 ce 33 0e   fmla    v5.2s, v18.2s, v19.2s
   649→//   10d34: 44 ce 34 0e   fmla    v4.2s, v18.2s, v20.2s
   650→//   10d38: 43 1a b1 0f   fmla    v3.2s, v18.2s, v17.s[3]
   651→//   10d3c: 61 fe ff 54   b.ne    0x10d08 <.text+0x770>
   652→//
   653→// This is effectively non-SIMD, since each of the 8 fmla here does one useful
   654→// scalar multiplication (note: the ldr s18 instruction loaded one float into
   655→// the first lane of v18.4s and zeroed the other 3 lanes).
   656→MMTKernel MMTKernel_8x1x1_f32f32f32_Aarch64_Baseline_InlineAsm() {
   657→  MMTKernel kernel;
   658→  kernel.lhsType = MMTKernel::ScalarType::F32;
   659→  kernel.rhsType = MMTKernel::ScalarType::F32;
   660→  kernel.accType = MMTKernel::ScalarType::F32;
   661→  kernel.m0 = 8;
   662→  kernel.k0 = 1;
   663→  kernel.n0 = 1;
   664→  kernel.lhsRegSize = 4;
   665→  kernel.rhsRegSize = 1;
   666→  kernel.accRegSize = 4;
   667→  kernel.lhsRegs = 2;
   668→  kernel.rhsRegs = 1;
   669→  kernel.accRegs = 2;
   670→  kernel.asmImpl = R"ASM(
   671→      fmla $(acc:0).4s, $(lhs:0).4s, $(rhs:0).s[0]
   672→      fmla $(acc:1).4s, $(lhs:1).4s, $(rhs:0).s[0]
   673→    )ASM";
   674→  return kernel;
   675→}
   676→
   677→// Constructs the mlir::Type corresponding to a scalar type.
   678→Type mlirType(MLIRContext *context, MMTKernel::ScalarType t) {
   679→  switch (t) {
   680→  case MMTKernel::ScalarType::None:
   681→    break;
   682→  case MMTKernel::ScalarType::I8:
   683→    return IntegerType::get(context, 8, IntegerType::Signless);
   684→  case MMTKernel::ScalarType::I32:
   685→    return IntegerType::get(context, 32, IntegerType::Signless);
   686→  case MMTKernel::ScalarType::F32:
   687→    return FloatType::getF32(context);
   688→  }
   689→  assert(false);
   690→  return Type();
   691→}
