   693→// This class is a helper for patterns generating custom kernels based on
   694→// MMTKernel structs.
   695→class MMTKernelGenerator {
   696→public:
   697→  MMTKernelGenerator(MLIRContext *context, MMTKernel kernel,
   698→                     IREE::HAL::ExecutableTargetAttr target)
   699→      : context(context), kernel(kernel), target(target) {
   700→    kernel.validate();
   701→  }
   702→  // Generates the kernel. Returns the output accumulator values.
   703→  SmallVector<Value> generate(PatternRewriter &rewriter, Location loc,
   704→                              ArrayRef<Value> lhs, ArrayRef<Value> rhs,
   705→                              ArrayRef<Value> acc) {
   706→    validateOperands(lhs, rhs, acc);
   707→    if (kernel.asmImpl) {
   708→      return generateAsm(rewriter, loc, lhs, rhs, acc);
   709→    }
   710→    // In the future we may have alternate generator paths, e.g. 1D intrinsics
   711→    // or other asm paths with a different interface, e.g. handling also
   712→    // the memory load accesses.
   713→    assert(false && "no implementation provided for kernel");
   714→    return {};
   715→  }
   716→  // Returns the MLIR element type (not vector type) of the LHS
   717→  Type getLhsType() const { return mlirType(context, kernel.lhsType); }
   718→  // Returns the MLIR element type (not vector type) of the RHS
   719→  Type getRhsType() const { return mlirType(context, kernel.rhsType); }
   720→  // Returns the MLIR element type (not vector type) of the Accumulator
   721→  Type getAccType() const { return mlirType(context, kernel.accType); }
   722→  // Returns the VectorType of LHS SIMD register vectors
   723→  VectorType getLhsRegVectorType() const {
   724→    return VectorType::get({kernel.lhsRegSize}, getLhsType());
   725→  }
   726→  // Returns the VectorType of RHS SIMD register vectors
   727→  VectorType getRhsRegVectorType() const {
   728→    return VectorType::get({kernel.rhsRegSize}, getRhsType());
   729→  }
   730→  // Returns the VectorType of Accumulator SIMD register vectors
   731→  VectorType getAccRegVectorType() const {
   732→    return VectorType::get({kernel.accRegSize}, getAccType());
   733→  }
   734→
   735→private:
   736→  MLIRContext *const context;
   737→  const MMTKernel kernel;
   738→  const IREE::HAL::ExecutableTargetAttr target;
   739→
   740→  // Helper for generate(). Asserts sanity of the vector-of-register-vectors.
   741→  void validateOperands(ArrayRef<Value> lhs, ArrayRef<Value> rhs,
   742→                        ArrayRef<Value> acc) {
   743→    auto validate = [](ArrayRef<Value> vals, int expectedSize,
   744→                       VectorType expectedType) {
   745→      assert(vals.size() == expectedSize);
   746→      for (const auto &val : vals) {
   747→        assert(dyn_cast<VectorType>(val.getType()) == expectedType);
   748→        (void)val;
   749→      }
   750→      (void)expectedSize;
   751→      (void)expectedType;
   752→    };
   753→    validate(lhs, kernel.lhsRegs, getLhsRegVectorType());
   754→    validate(rhs, kernel.rhsRegs, getRhsRegVectorType());
   755→    validate(acc, kernel.accRegs, getAccRegVectorType());
   756→  }
   757→  // Helper for generateAsmCodeAndConstraints
   758→  std::string getConstraintCode() const {
   759→    if (isAArch64(target)) {
   760→      return "w";
   761→    }
   762→    assert(false && "what constraint code to use on this arch?");
   763→    return {};
   764→  }
   765→  // Helper class to build the constraints string of an inline_asm op.
   766→  class Constraints {
   767→  private:
   768→    // The LLVM inline asm syntax is documented here:
   769→    // https://llvm.org/docs/LangRef.html#inline-assembler-expressions
   770→    SmallVector<std::string> inputs;
   771→    SmallVector<std::string> outputs;
   772→    SmallVector<std::string> tiedInputs;
   773→    SmallVector<std::string> clobbers;
   774→
   775→  public:
   776→    enum class Kind { Input, InputOutput };
   777→    // Add a new constraint.
   778→    void add(Kind kind, const std::string &constraintCode) {
   779→      switch (kind) {
   780→      case Kind::Input:
   781→        inputs.push_back(constraintCode);
   782→        return;
   783→      case Kind::InputOutput:
   784→        // An input represented by a number `i` is a tied input, tied to the
   785→        // i-th output.
   786→        tiedInputs.push_back(llvm::itostr(outputs.size()));
   787→        outputs.push_back(std::string("=") + constraintCode);
   788→        return;
   789→      }
   790→      assert(false);
   791→    }
   792→    void setClobbers(const char *rawClobbersStr) {
   793→      assert(clobbers.empty());
   794→      if (!rawClobbersStr) {
   795→        return;
   796→      }
   797→      for (StringRef c : llvm::split(rawClobbersStr, ',')) {
   798→        clobbers.push_back(("~{" + c + "}").str());
   799→      }
   800→    }
   801→    // Returns the constraints string to be passed to the inline_asm op.
   802→    // llvm::concat does not currently support concatenating const-qualified
   803→    // objects, so we can't currently const-qualify this method.
   804→    std::string toString() {
   805→      return llvm::join(
   806→          llvm::concat<std::string>(outputs, inputs, tiedInputs, clobbers),
   807→          ",");
   808→    }
   809→  };
   810→  // Helper for generateAsm. Performs some pre-processing of the kernel's
   811→  // asmImpl. Refer to the comment on kernel::asmImpl.
   812→  void generateAsmCodeAndConstraints(std::string &code,
   813→                                     std::string &constraintsString) {
   814→    assert(code.empty());
   815→    assert(constraintsString.empty());
   816→    // The LLVM inline asm syntax is documented here:
   817→    // https://llvm.org/docs/LangRef.html#inline-assembler-expressions
   818→    Constraints constraints;
   819→    code = kernel.asmImpl;
   820→    // processedIdx is the index of a register in the processed asm.
   821→    // Example:   $5   =>   processedIdx == 5
   822→    int processedIdx = 0;
   823→    auto processOperands = [&](Constraints::Kind constraintKind,
   824→                               const char *name, int count) {
   825→      const std::string &constraintCode = getConstraintCode();
   826→      // unprocessedIdx is the index of a register in the unprocessed asm.
   827→      // Example:   $(lhs:1)   =>   unprocessedIdx == 1
   828→      for (int unprocessedIdx = 0; unprocessedIdx < count;
   829→           ++unprocessedIdx, ++processedIdx) {
   830→        constraints.add(constraintKind, constraintCode);
   831→        // Perform the code replacement for the operand.
   832→        // Example:   $(lhs:1)   =>   $5
   833→        replaceAllSubstrsInPlace(
   834→            code, llvm::formatv("$({}:{})", name, unprocessedIdx),
   835→            llvm::formatv("${}", processedIdx));
   836→      }
   837→    };
   838→    processOperands(Constraints::Kind::InputOutput, "acc", kernel.accRegs);
   839→    processOperands(Constraints::Kind::Input, "lhs", kernel.lhsRegs);
   840→    processOperands(Constraints::Kind::Input, "rhs", kernel.rhsRegs);
   841→    constraints.setClobbers(kernel.asmClobbers);
   842→    constraintsString = constraints.toString();
   843→  }
   844→  // Helper for generate(). Implements the asm path.
   845→  SmallVector<Value> generateAsm(PatternRewriter &rewriter, Location loc,
   846→                                 ArrayRef<Value> lhs, ArrayRef<Value> rhs,
   847→                                 ArrayRef<Value> acc) {
   848→    SmallVector<Value> inputs;
   849→    // First the input operands. Then the input-output operands, which, as far
   850→    // as input constraints are concerned, are *tied* inputs, i.e. refer to
   851→    // the outputs that we list earlier in the constraints string. This is why
   852→    // us passing the inputs BEFORE the input-outputs here actually matches
   853→    // us listing the inputs AFTER the outputs (but BEFORE the tied-inputs) in
   854→    // the constraints string. Not confusing at all!
   855→    inputs.append(lhs.begin(), lhs.end());
   856→    for (const auto &v : rhs) {
   857→      if (llvm::cast<VectorType>(v.getType()).getNumElements() == 1)
   858→        inputs.push_back(extract(rewriter, loc, v, 0));
   859→      else
   860→        inputs.push_back(v);
   861→    }
   862→    inputs.append(acc.begin(), acc.end());
   863→    // Create the inline asm op.
   864→    SmallVector<Type> outputOperandTypes(
   865→        llvm::map_range(acc, [](Value v) { return v.getType(); }));
   866→    auto returnType =
   867→        LLVM::LLVMStructType::getLiteral(context, outputOperandTypes);
   868→    auto dialectAttr =
   869→        LLVM::AsmDialectAttr::get(context, LLVM::AsmDialect::AD_ATT);
   870→    std::string code;
   871→    std::string constraints;
   872→    generateAsmCodeAndConstraints(code, constraints);
   873→    LLVM::InlineAsmOp asmOp = rewriter.create<LLVM::InlineAsmOp>(
   874→        loc, returnType, inputs, code, constraints,
   875→        /*has_side_effects=*/false, /*is_align_stack=*/false, dialectAttr,
   876→        /*operand_attrs=*/ArrayAttr());
   877→    // Extract result vectors from the asm op.
   878→    SmallVector<Value> resVec;
   879→    for (int i = 0; i < kernel.accRegs; ++i) {
   880→      SmallVector<int64_t, 1> position = {i};
   881→      resVec.push_back(
   882→          rewriter.create<LLVM::ExtractValueOp>(loc, asmOp.getRes(), position));
   883→    }
   884→    return resVec;
   885→  }
   886→};
   887→
   888→/// Converts matrix-times-matrix-transposed vector.contracts, and possibly also
   889→/// any type-promotion op (such as arith.extsi) on the input operands, to
   890→/// a custom kernel (at the moment a llvm.inline_asm op) provided by the
   891→/// MMTKernel struct.
   892→///
   893→/// For example, in the case of a i8*i8->i32 kernel, the IR being replaced
   894→/// by the llvm.inline_asm op might look like:
   895→///
   896→///     %lhs_i32 = arith.extsi %lhs_i8 : i8 to i32
   897→///     %rhs_i32 = arith.extsi %rhs_i8 : i8 to i32
   898→///     %result = vector.contract [...]
   899→///                 %lhs_i32 : vector<8x4xi32>,
   900→///                 %rhs_i32 : vector<8x4xi32>,
   901→///                 %acc_i32 : vector<8x8xi32>,
   902→///                 [...]
   903→///
   904→class MMTCustomKernelPattern : public OpRewritePattern<vector::ContractionOp> {
   905→private:
   906→  MMTKernel kernel;
   907→
   908→public:
   909→  MMTCustomKernelPattern(MLIRContext *context, MMTKernel kernel)
   910→      : OpRewritePattern<vector::ContractionOp>(context), kernel(kernel) {}
   911→
   912→  LogicalResult matchAndRewrite(vector::ContractionOp contractionOp,
   913→                                PatternRewriter &rewriter) const override {
   914→    // Check if `contractionOp` matches, and obtain the (un-promoted) input
   915→    // LHS and RHS vectors.
   916→    bool transposeKernel = false;
   917→    if (!matchMMT(contractionOp, kernel.m0, kernel.k0, kernel.n0,
   918→                  &transposeKernel)) {
   919→      return failure();
   920→    }
   921→    auto target = IREE::HAL::ExecutableTargetAttr::lookup(contractionOp);
   922→    MMTKernelGenerator generator(rewriter.getContext(), kernel, target);
   923→    Type lhsElemType = generator.getLhsType();
   924→    Type rhsElemType = generator.getRhsType();
   925→    Type accElemType = generator.getAccType();
   926→    VectorType accType =
   927→        llvm::cast<VectorType>(contractionOp.getAcc().getType());
   928→    if (accType.getElementType() != accElemType) {
   929→      return failure();
   930→    }
   931→    Value unpromotedLhs =
   932→        getUnpromotedInput(lhsElemType, accElemType, contractionOp.getLhs());
   933→    Value unpromotedRhs =
   934→        getUnpromotedInput(rhsElemType, accElemType, contractionOp.getRhs());
   935→    if (!unpromotedLhs || !unpromotedRhs) {
   936→      return failure();
   937→    }
   938→    // Prepare the dense array attribute that will be used as the initializer
   939→    // for the destination accumulator vector, before actual values are inserted
   940→    // into it. We do this early because here we need to validate that the
   941→    // destination scalar type is one that we know how to handle.
   942→    VectorType flatAccVectorType =
   943→        VectorType::get({accType.getNumElements()}, accType.getElementType());
   944→    ;
   945→    TypedAttr resultInitializer;
   946→    if (accElemType.isSignlessInteger()) {
   947→      resultInitializer = DenseIntElementsAttr::get(flatAccVectorType, 0);
   948→    } else if (accElemType.isF32()) {
   949→      resultInitializer = DenseFPElementsAttr::get(flatAccVectorType, 0.f);
   950→    } else {
   951→      return failure();
   952→    }
   953→    // `contractionOp` matches, start rewriting it.
   954→    Location loc = contractionOp.getLoc();
   955→    // Flatten the inputs to 1D vectors.
   956→    Value flatLhs = flatten(rewriter, loc, unpromotedLhs);
   957→    Value flatRhs = flatten(rewriter, loc, unpromotedRhs);
   958→    Value flatAcc = flatten(rewriter, loc, contractionOp.getAcc());
   959→    // Slice into SIMD-register-sized 1D input vectors ready to feed to the
   960→    // target SIMD instructions.
   961→    auto sliceIntoRegVectors = [&](int regsCount, VectorType regVectorType,
   962→                                   Value src) {
   963→      SmallVector<Value> regVectors;
   964→      int regSize = regVectorType.getNumElements();
   965→      for (int i = 0; i < regsCount; ++i) {
   966→        regVectors.push_back(
   967→            extract1DSlice(rewriter, loc, regVectorType, src, i * regSize));
   968→      }
   969→      return regVectors;
   970→    };
   971→    VectorType lhsRegVectorType = generator.getLhsRegVectorType();
   972→    VectorType rhsRegVectorType = generator.getRhsRegVectorType();
   973→    VectorType accRegVectorType = generator.getAccRegVectorType();
   974→    Value flatLhsForKernel = transposeKernel ? flatRhs : flatLhs;
   975→    Value flatRhsForKernel = transposeKernel ? flatLhs : flatRhs;
   976→    SmallVector<Value> lhsRegVectors =
   977→        sliceIntoRegVectors(kernel.lhsRegs, lhsRegVectorType, flatLhsForKernel);
   978→    SmallVector<Value> rhsRegVectors =
   979→        sliceIntoRegVectors(kernel.rhsRegs, rhsRegVectorType, flatRhsForKernel);
   980→    SmallVector<Value> accRegVectors =
   981→        sliceIntoRegVectors(kernel.accRegs, accRegVectorType, flatAcc);
   982→    // Generate the kernel!
   983→    SmallVector<Value> resRegVectors = generator.generate(
   984→        rewriter, loc, lhsRegVectors, rhsRegVectors, accRegVectors);
   985→    // Insert the result vectors of size 4 into the overall result vector of
   986→    // size 64, still 1D.
   987→    Value result = rewriter.create<arith::ConstantOp>(loc, flatAccVectorType,
   988→                                                      resultInitializer);
   989→    int accRegNumElements = accRegVectorType.getNumElements();
   990→    for (int i = 0; i < kernel.accRegs; ++i) {
   991→      result = rewriter.create<vector::InsertStridedSliceOp>(
   992→          loc, resRegVectors[i], result,
   993→          std::array<int64_t, 1>{accRegNumElements * i},
   994→          std::array<int64_t, 1>{1});
   995→    }
   996→    // Cast the result from 1D to 2D and replace the original vector.contract.
   997→    rewriter.replaceOpWithNewOp<vector::ShapeCastOp>(contractionOp, accType,
   998→                                                     result);
   999→    return success();
  1000→  }
  1001→};
