  1003→/// Converts matrix-times-matrix-transposed vector.contracts with
  1004→/// lhs and rhs inputs defined by arith.extsi promoting from i8 to i32,
  1005→///
  1006→///     %lhs_i32 = arith.extsi %lhs_i8 : i8 to i32
  1007→///     %rhs_i32 = arith.extsi %rhs_i8 : i8 to i32
  1008→///     %result = vector.contract [...]
  1009→///                 %lhs_i32 : vector<8x4xi32>,
  1010→///                 %rhs_i32 : vector<8x4xi32>,
  1011→///                 %acc_i32 : vector<8x8xi32>,
  1012→///                 [...]
  1013→///
  1014→/// To vector ops reading directly from the %lhs_i8 and %rhs_i8 values
  1015→/// (bypassing the existing arith.extsi) and passing that to a llvm.inline_asm
  1016→/// block implementing the matrix multiplication arithmetic using Aarch64
  1017→/// dot-product instructions (sdot).
  1018→/// It matches the same patterns as MMT_8x4x8_i8i8i32_Aarch64Dotprod_InlineAsm
  1019→struct MMT_8x4x8_i8i8i32_Aarch64Dotprod_Intrinsics
  1020→    : public OpRewritePattern<vector::ContractionOp> {
  1021→public:
  1022→  using OpRewritePattern<vector::ContractionOp>::OpRewritePattern;
  1023→
  1024→  LogicalResult matchAndRewrite(vector::ContractionOp contractionOp,
  1025→                                PatternRewriter &rewriter) const override {
  1026→    if (!matchMMT(contractionOp, 8, 4, 8)) {
  1027→      return failure();
  1028→    }
  1029→
  1030→    Type I8Type = rewriter.getIntegerType(8);
  1031→    Type I32Type = rewriter.getIntegerType(32);
  1032→
  1033→    auto acc = contractionOp.getAcc();
  1034→    auto lhs = contractionOp.getLhs();
  1035→    auto rhs = contractionOp.getRhs();
  1036→    if (llvm::cast<VectorType>(acc.getType()).getElementType() != I32Type) {
  1037→      return failure();
  1038→    }
  1039→
  1040→    Value inLhs = getUnpromotedInput(I8Type, I32Type, lhs);
  1041→    Value inRhs = getUnpromotedInput(I8Type, I32Type, rhs);
  1042→
  1043→    if (!inLhs || !inRhs)
  1044→      return failure();
  1045→
  1046→    auto loc = contractionOp.getLoc();
  1047→
  1048→    auto int32x4VType = VectorType::get({4}, I32Type);
  1049→
  1050→    std::array<Value, 16> accChunks;
  1051→    {
  1052→      int idx = 0;
  1053→      for (int row = 0; row < 8; ++row) {
  1054→        auto accRow = rewriter.create<vector::ExtractOp>(
  1055→            loc, acc, ArrayRef<int64_t>{row});
  1056→        for (int col = 0; col < 8; col += 4) {
  1057→          auto accChunk = rewriter.create<vector::ExtractStridedSliceOp>(
  1058→              loc, accRow, ArrayRef<int64_t>{col}, ArrayRef<int64_t>{4},
  1059→              ArrayRef<int64_t>{1});
  1060→          assert(accChunk.getType() == int32x4VType);
  1061→          accChunks[idx++] = accChunk;
  1062→        }
  1063→      }
  1064→    }
  1065→
  1066→    auto int8x4x4VType = VectorType::get({4, 4}, rewriter.getIntegerType(8));
  1067→    auto extract4x4 = [&](Value in, int rowOffset, int colOffset) {
  1068→      auto chunk = rewriter.create<vector::ExtractStridedSliceOp>(
  1069→          loc, in, ArrayRef<int64_t>{rowOffset, colOffset},
  1070→          ArrayRef<int64_t>{4, 4}, ArrayRef<int64_t>{1, 1});
  1071→      assert(chunk.getType() == int8x4x4VType);
  1072→      return chunk;
  1073→    };
  1074→
  1075→    std::array<Value, 2> lhsHalves = {extract4x4(inLhs, 0, 0),
  1076→                                      extract4x4(inLhs, 4, 0)};
  1077→    std::array<Value, 2> rhsHalves = {extract4x4(inRhs, 0, 0),
  1078→                                      extract4x4(inRhs, 4, 0)};
  1079→
  1080→    auto int8Zero4x4 = rewriter.create<arith::ConstantOp>(
  1081→        loc, rewriter.getZeroAttr(int8x4x4VType));
  1082→    auto sdot = [&](Value acc, Value a, Value b, int64_t lane) -> Value {
  1083→      auto bReplicatedLane = rewriter.create<vector::ShuffleOp>(
  1084→          loc, b, int8Zero4x4, ArrayRef<int64_t>{lane, lane, lane, lane});
  1085→
  1086→      return rewriter.create<arm_neon::Sdot2dOp>(loc, int32x4VType, acc, a,
  1087→                                                 bReplicatedLane);
  1088→    };
  1089→
  1090→    std::array<Value, 16> dstChunks;
  1091→    {
  1092→      int idx = 0;
  1093→      for (Value lhs : lhsHalves) {
  1094→        for (int lane = 0; lane < 4; ++lane) {
  1095→          for (Value rhs : rhsHalves) {
  1096→            dstChunks[idx] = sdot(accChunks[idx], rhs, lhs, lane);
  1097→            ++idx;
  1098→          }
  1099→        }
  1100→      }
  1101→    }
  1102→
  1103→    // Put the results back in the accumulator
  1104→    {
  1105→      int idx = 0;
  1106→      for (int row = 0; row < 8; ++row) {
  1107→        for (int col = 0; col < 8; col += 4) {
  1108→          acc = rewriter.create<vector::InsertStridedSliceOp>(
  1109→              loc, dstChunks[idx++], acc, ArrayRef<int64_t>{row, col},
  1110→              ArrayRef<int64_t>{1});
  1111→        }
  1112→      }
  1113→    }
  1114→    rewriter.replaceOp(contractionOp, {acc});
  1115→    return success();
  1116→  }
  1117→};
