  1119→class VectorContractCustomKernelsPass
  1120→    : public impl::VectorContractCustomKernelsPassBase<
  1121→          VectorContractCustomKernelsPass> {
  1122→public:
  1123→  void getDependentDialects(DialectRegistry &registry) const override {
  1124→    registry.insert<vector::VectorDialect, LLVM::LLVMDialect,
  1125→                    arm_neon::ArmNeonDialect>();
  1126→  }
  1127→  void runOnOperation() override {
  1128→    MLIRContext *context = &getContext();
  1129→    RewritePatternSet patterns(context);
  1130→    auto funcOp = getOperation();
  1131→    auto target = IREE::HAL::ExecutableTargetAttr::lookup(funcOp);
  1132→    populateVectorContractCustomKernelsPatterns(target, patterns);
  1133→    if (failed(applyPatternsGreedily(funcOp, std::move(patterns)))) {
  1134→      signalPassFailure();
  1135→    }
  1136→  }
  1137→};
