  1140→
  1141→void populateVectorContractCustomKernelsPatterns(
  1142→    IREE::HAL::ExecutableTargetAttr target, RewritePatternSet &patterns) {
  1143→  MLIRContext *context = patterns.getContext();
  1144→  if (isAArch64(target)) {
  1145→    // TODO: add a "kernel benefit" system whereby if two kernels are available
  1146→    // for the same shape and same data types, the fastest one (ie the one
  1147→    // using the most powerful available SIMD instructions) is selected.
  1148→    // This is incidentally not needed at the moment because currently no two
  1149→    // kernels share the exact same shape and data types.
  1150→    patterns.add<MMTCustomKernelPattern>(
  1151→        context, MMTKernel_8x1x8_f32f32f32_Aarch64_Baseline_InlineAsm());
  1152→    patterns.add<MMTCustomKernelPattern>(
  1153→        context, MMTKernel_8x1x1_f32f32f32_Aarch64_Baseline_InlineAsm());
  1154→    patterns.add<MMTCustomKernelPattern>(
  1155→        context, MMTKernel_8x1x8_i8i8i32_Aarch64_Baseline_InlineAsm());
  1156→    patterns.add<MMTCustomKernelPattern>(
  1157→        context, MMTKernel_8x8x1_i8i8i32_Aarch64_Baseline_InlineAsm());
  1158→    if (hasFeature(target, "+dotprod")) {
  1159→      if (preferIntrinsicsOverAsm(target)) {
  1160→        patterns.add<MMT_8x4x8_i8i8i32_Aarch64Dotprod_Intrinsics>(context);
  1161→      } else {
  1162→        patterns.add<MMTCustomKernelPattern>(
  1163→            context, MMTKernel_8x4x8_i8i8i32_Aarch64Dotprod_InlineAsm());
  1164→        patterns.add<MMTCustomKernelPattern>(
  1165→            context, MMTKernel_8x4x1_i8i8i32_Aarch64Dotprod_InlineAsm());
  1166→      }
  1167→    }
  1168→    if (hasFeature(target, "+i8mm")) {
  1169→      patterns.add<MMTCustomKernelPattern>(
  1170→          context, MMTKernel_8x8x8_i8i8i32_Aarch64I8mm_InlineAsm());
  1171→    }
  1172→  }
  1173→}
