    38→/// Verify that valid configuration is set for all ops within the funcOp.
    39→template <typename F>
    40→static LogicalResult
    41→verifyLoweringConfiguration(FunctionOpInterface funcOp,
    42→                            IREE::Codegen::TranslationInfoAttr translationInfo,
    43→                            F verificationFn) {
    44→  auto walkResult = funcOp.walk([&](Operation *op) -> WalkResult {
    45→    if (isa<IREE::LinalgExt::CustomOp>(op)) {
    46→      return WalkResult::advance();
    47→    }
    48→    auto loweringConfig =
    49→        getLoweringConfig<IREE::Codegen::LoweringConfigAttr>(op);
    50→    if (!loweringConfig)
    51→      return WalkResult::advance();
    52→    TilingConfig tilingConfig(loweringConfig);
    53→    return verificationFn(op, tilingConfig, translationInfo,
    54→                          ArrayRef<int64_t>{});
    55→  });
    56→  return failure(walkResult.wasInterrupted());
    57→}
    58→
    59→void LLVMCPUSelectLoweringStrategyPass::runOnOperation() {
    60→  auto moduleOp = getOperation();
    61→  for (auto funcOp : moduleOp.getOps<FunctionOpInterface>()) {
    62→    // Set the strategy with default heuristics.
    63→    if (failed(initCPULaunchConfig(funcOp))) {
    64→      funcOp.emitOpError("failed to set lowering configuration");
    65→      return signalPassFailure();
    66→    }
    67→
    68→    auto translationInfo = getTranslationInfo(funcOp);
    69→    if (!translationInfo) {
    70→      continue;
    71→    }
    72→
    73→    // Verify the configuration.
    74→    LogicalResult verificationStatus = success();
    75→    switch (translationInfo.getDispatchLoweringPassPipeline()) {
    76→    case IREE::Codegen::DispatchLoweringPassPipeline::CPUDoubleTilingExpert:
    77→      verificationStatus = verifyLoweringConfiguration(
    78→          funcOp, translationInfo, verifyDoubleTilingExpertPassPipelineConfig);
    79→      break;
    80→    case IREE::Codegen::DispatchLoweringPassPipeline::
    81→        CPUConvTileAndDecomposeExpert:
    82→      verificationStatus = verifyLoweringConfiguration(
    83→          funcOp, translationInfo, verifyConvTileAndDecomposeExpertConfig);
    84→      break;
    85→    default:
    86→      break;
    87→    }
    88→    if (failed(verificationStatus)) {
    89→      return signalPassFailure();
    90→    }
    91→  }
    92→}
    93→} // namespace mlir::iree_compiler
