   205→/// Returns the vectorization pre-processing strategy (peeling, masking) for the
   206→/// given LinalgOp. It is based on either (in the priority order):
   207→///   * user-specified value, or
   208→///   * IREE's heuristics (e.g. the op traits and the target architecture).
   209→static VectorPreProcStrategy
   210→getVectorPreProcStrategy(linalg::LinalgOp linalgOp) {
   211→  // If set, use the strategy selected by a user.
   212→  if (clPProcStrategy.getNumOccurrences()) {
   213→    return clPProcStrategy;
   214→  }
   215→
   216→  // TODO: Implement heuristics for Convs
   217→  if (isa<linalg::ConvolutionOpInterface>(linalgOp.getOperation())) {
   218→    return VectorPreProcStrategy::None;
   219→  }
   220→
   221→  // Select a strategy based on heuristics.
   222→  if (linalgOp.hasPureBufferSemantics()) {
   223→    return VectorPreProcStrategy::None;
   224→  }
   225→
   226→  // Walk the linalgOp code, if there is any instruction that could result in
   227→  // undefined behavior in mask strategy, fall back to using peel strategy.
   228→  bool usePeelingStrategy = false;
   229→  linalgOp.walk([&](Operation *op) -> WalkResult {
   230→    if (mlir::iree_compiler::mayHaveUndefinedBehaviorInMasking(op)) {
   231→      usePeelingStrategy = true;
   232→      return WalkResult::interrupt();
   233→    }
   234→    return WalkResult::advance();
   235→  });
   236→  if (usePeelingStrategy) {
   237→    return VectorPreProcStrategy::Peeling;
   238→  }
   239→
   240→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(linalgOp);
   241→  bool isLinalgGeneric = isa<linalg::GenericOp>(linalgOp.getOperation());
   242→
   243→  // Default X86 specific strategy.
   244→  if (isX86(targetAttr)) {
   245→    if (isLinalgGeneric) {
   246→      return VectorPreProcStrategy::Masking;
   247→    }
   248→
   249→    if (!clDisableVectorPeeling) {
   250→      return VectorPreProcStrategy::Peeling;
   251→    }
   252→  }
   253→
   254→  // Default RISC-V specific strategies.
   255→  if (isRISCV(targetAttr)) {
   256→    if (isLinalgGeneric) {
   257→      return VectorPreProcStrategy::Masking;
   258→    }
   259→
   260→    if (!clDisableVectorPeeling) {
   261→      return VectorPreProcStrategy::Peeling;
   262→    }
   263→  }
   264→
   265→  // Default AArch64 specific strategies.
   266→  if (isAArch64(targetAttr)) {
   267→    if (clEnableScalableVectorization && hasAnySVEFeature(targetAttr)) {
   268→      return VectorPreProcStrategy::Masking;
   269→    }
   270→
   271→    if (!clDisableVectorPeeling) {
   272→      return VectorPreProcStrategy::Peeling;
   273→    }
   274→  }
   275→
   276→  return VectorPreProcStrategy::None;
   277→}
