   295→/// Looks for the `native_vector_size` attribute in the hal.executable.target
   296→/// looked up from this op.
   297→static int64_t
   298→getNativeVectorSizeInBytes(mlir::FunctionOpInterface entryPointFn) {
   299→  auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(entryPointFn);
   300→  auto nativeVectorSizeAttr =
   301→      getConfigIntegerAttr(targetAttr, "native_vector_size");
   302→  if (nativeVectorSizeAttr) {
   303→    int64_t nativeVectorSizeVal = nativeVectorSizeAttr->getInt();
   304→    if (nativeVectorSizeVal) {
   305→      return nativeVectorSizeVal;
   306→    }
   307→  }
   308→
   309→  assert(0 && "Missing 'native_vector_size' attribute");
   310→  return 0;
   311→}
