   329→/// Returns true if the operation is a GenericOp implementing a supported
   330→/// transposition:
   331→///   1. The op has a single input and a single output.
   332→///   2. One of the indexing_map is identity and the other is a permutation.
   333→static bool x86TransposeLoweringPrecondition(linalg::GenericOp genericOp) {
   334→  // Check that the op has at least 2 dimensions.
   335→  if (genericOp.getNumLoops() < 2) {
   336→    return false;
   337→  }
   338→
   339→  // Check that the op has only one input and one output.
   340→  // TODO(diegocaballero): Generalize to multiple inputs.
   341→  if ((genericOp.getNumDpsInputs() != 1) || (genericOp.getNumDpsInits() != 1)) {
   342→    return false;
   343→  }
   344→
   345→  // Check that all the iterators are parallel.
   346→  if (genericOp.getNumParallelLoops() != genericOp.getNumLoops()) {
   347→    return false;
   348→  }
