    37→/// Returns a VectorizationTileSizes which contains the inferred bounded result
    38→/// shape and vector input sizes. This is useful to infer the sizes from a
    39→/// chain.
    40→static std::optional<VectorizationTileSizes> inferSizesFromIR(Value val);
    41→
    42→/// Tries to infer the vector sizes from an IR using ValueBounds analysis. If
    43→/// `opResult` is provided, it stores the bounded result shapes to destShape.
    44→/// Returns std::nullopt if vector sizes can't be inferred.
    45→static std::optional<VectorizationTileSizes>
    46→inferSizesFromIR(linalg::LinalgOp linalgOp, std::optional<OpResult> opResult) {
    47→  LLVM_DEBUG({
    48→    VEC_DBGS() << "Inferring sizes for:\n" << linalgOp;
    49→    if (opResult) {
    50→      VEC_DBGS() << " with OpResult.resultNumber="
    51→                 << opResult->getResultNumber();
    52→    }
    53→    VEC_DBGS() << '\n';
    54→  });
    55→
    56→  std::optional<vector::VscaleRange> vscaleRange;
    57→  if (!opResult) {
    58→    // Note: Inferring scalable sizes is not supported is `opResult` is set
    59→    // (which is used to compute sizes for tensor.pack/unpack).
    60→    auto targetAttr = IREE::HAL::ExecutableTargetAttr::lookup(linalgOp);
    61→    vscaleRange = getDefaultVscaleRange(targetAttr);
    62→  }
    63→
    64→  VectorizationTileSizes result;
    65→  unsigned numDims = linalgOp.getNumLoops();
    66→  for (int dim = 0; dim < numDims; ++dim) {
    67→    // Map dimension `dim` to an operand dimension that we will use to
    68→    // traverse the U-D chain to get `dim` vector size information.
    69→    SmallVector<std::pair<Value, unsigned>> operandDimPairs;
    70→    linalgOp.mapIterationSpaceDimToAllOperandDims(dim, operandDimPairs);
    71→    if (operandDimPairs.empty()) {
    72→      return std::nullopt;
    73→    }
    74→
    75→    Value firstOperand = operandDimPairs[0].first;
    76→    unsigned firstOperandDim = operandDimPairs[0].second;
    77→
    78→    // Trivial case: `dim` size is available in the operand type.
    79→    int64_t dimSize = llvm::cast<ShapedType>(firstOperand.getType())
    80→                          .getShape()[firstOperandDim];
    81→    bool dimScalable = false;
    82→    if (!ShapedType::isDynamic(dimSize)) {
    83→      result.vectorSizes.push_back(dimSize);
    84→      result.vectorScalableFlags.push_back(dimScalable);
    85→      LLVM_DEBUG(VEC_DBGS() << "Inferred iteration size '" << dimSize
    86→                            << "' for dimension '" << dim << "'\n");
    87→      continue;
    88→    }
    89→
    90→    // Use ValueBounds analysis to infer `dim` size upper bound.
    91→    FailureOr<DimBoundSize> maybeDimBound;
    92→    for (auto operandDimPair : operandDimPairs) {
    93→      Value operand = operandDimPair.first;
    94→      unsigned operandDim = operandDimPair.second;
    95→      maybeDimBound = computeDimUpperBound(operand, operandDim, vscaleRange,
    96→                                           RoundUpVscaleMultiple::Yes);
    97→      if (succeeded(maybeDimBound)) {
    98→        break;
    99→      }
   100→    }
   101→
   102→    if (failed(maybeDimBound)) {
   103→      return std::nullopt;
   104→    }
   105→
   106→    dimSize = maybeDimBound->baseSize;
   107→    dimScalable = maybeDimBound->scalable;
   108→    result.vectorSizes.push_back(dimSize);
   109→    result.vectorScalableFlags.push_back(dimScalable);
   110→
   111→    LLVM_DEBUG(VEC_DBGS() << "Inferred iteration size '" << dimSize
   112→                          << (dimScalable ? " x vscale" : "")
   113→                          << "' for dimension '" << dim << "'\n");
   114→  }
   115→
   116→  if (opResult) {
   117→    assert(!llvm::is_contained(result.vectorScalableFlags, true) &&
   118→           "inferring scalable bounds with `opResult` not supported!");
   119→    result.destShape = linalgOp.getIndexingMapMatchingResult(opResult.value())
   120→                           .compose(result.vectorSizes);
   121→  }
   122→
   123→  return result;
   124→}
