   623→/// Computes the maximum tile size that can be used to vectorize (or unroll) a
   624→/// dimension based on its number of elements and the native vector size of
   625→/// the target. If `enforcePowerOfTwo` is set to true, the resulting tile size
   626→/// will be a power of two.
   627→static int64_t getMaxVectorTileSize(int64_t numElem, int64_t tileSize,
   628→                                    int64_t vectorSize,
   629→                                    bool enforcePowerOfTwo = false) {
   630→  if (ShapedType::isDynamic(numElem)) {
   631→    return roundUpToPow2(tileSize, enforcePowerOfTwo);
   632→  }
   633→  if (numElem <= tileSize && numElem < vectorSize) {
   634→    return roundUpToPow2(numElem, enforcePowerOfTwo);
   635→  }
   636→
   637→  // Return the largest suitable power of two if power of two is enforced.
   638→  if (enforcePowerOfTwo) {
   639→    return roundUpToPow2(std::min(tileSize, numElem), enforcePowerOfTwo);
   640→  }
   641→
   642→  // Try to find a tile size that is multiple of the vector size.
   643→  int64_t scaledUB = std::min(tileSize, numElem) / vectorSize * vectorSize;
   644→  for (int64_t i = scaledUB; i > 0; i -= vectorSize) {
   645→    if (numElem % i == 0) {
   646→      return i;
   647→    }
   648→  }
   649→
   650→  // If it can't be a multiple of `vectorSize`, let's choose a factor of
   651→  // `numElem` sizes heuristically.
   652→  int64_t start = std::min(tileSize, numElem);
   653→  for (int64_t i = start; i > 0; --i) {
   654→    if (numElem % i == 0) {
   655→      return i;
   656→    }
   657→  }
   658→
   659→  return 1;
   660→}
