   662→// Returns true if `map` is a function of `dim` and is not a function of any
   663→// more inner dimensions past `dim`.
   664→static bool isInnerMostDimThatMapIsFunctionOf(AffineMap map, int dim) {
   665→  if (!map.isFunctionOfDim(dim)) {
   666→    return false;
   667→  }
   668→  for (int d = dim + 1; d < map.getNumDims(); ++d) {
   669→    if (map.isFunctionOfDim(d)) {
   670→      return false;
   671→    }
   672→  }
   673→  return true;
   674→}
   675→
   676→// Clamps in-place `vecTileSizes`, ensuring that the resulting vector tile sizes
   677→// for each opearand of `op` satisfy two requirements:
   678→// 1. No resulting operand tile size exceeds `eachOperandMaxTileBits`.
   679→// 2. The sum of all resulting operand tile size does not exceed
   680→// `allOperandsMaxTileBits`.
   681→static void limitVectorTileSizes(linalg::LinalgOp op,
   682→                                 SmallVectorImpl<int64_t> &vecTileSizes,
   683→                                 int64_t eachOperandMaxTileBits,
   684→                                 int64_t allOperandsMaxTileBits) {
   685→  int numLoops = op.getNumLoops();
   686→  assert(numLoops == vecTileSizes.size());
   687→  auto indexingMaps = op.getIndexingMapsArray();
   688→  auto operandTypes = op->getOperandTypes();
   689→  int numOperands = operandTypes.size();
   690→
   691→  SmallVector<int64_t> operandElemBits =
   692→      llvm::map_to_vector(op->getOperandTypes(), [](Type t) -> int64_t {
   693→        return IREE::Util::getTypeBitWidth(getElementTypeOrSelf(t));
   694→      });
   695→
   696→  // For each operand, we track how big the tile is going to be based on the
   697→  // dimensions that we have already accounted for. Here we initialize this to
   698→  // just elemBitWidth, having not yet accounted for any array dimension.
   699→  SmallVector<int64_t> tileBits;
   700→  for (auto bits : operandElemBits) {
   701→    if (bits > eachOperandMaxTileBits) {
   702→      // eachOperandMaxTileBits is too small for this requirement to be
   703→      // satisfied. Early-returning. This might conceivably happen due to the
   704→      // tail-recursion in this function, where eachOperandMaxTileBits is
   705→      // halved.
   706→      return;
   707→    }
   708→    tileBits.push_back(bits);
   709→  }
   710→
   711→  // For each loop, we must make sure that if it's the inner-most dimension that
   712→  // concerns an operand with a not-multiple-of-8-bit element type, we preserve
   713→  // the requirement that the inner-most tile dimension is a multiple of 8 bits.
   714→  // For example, if the element type is `i2`, the minimum inner tile size is
   715→  // 8/2 = 4. If the element type if i6, since gcd(8, 6) = 2, we are in the same
   716→  // situation and the minimum inner tile size is again 8/2 = 4.
   717→  // TODO(#17178): check this actually works when we have such element types.
   718→  SmallVector<int64_t> minVecTileSizes(numLoops, 1);
   719→  for (int loopNum : llvm::seq<int>(0, numLoops)) {
   720→    for (int i : llvm::seq<int>(0, numOperands)) {
   721→      if (isInnerMostDimThatMapIsFunctionOf(indexingMaps[i], loopNum)) {
   722→        if (operandElemBits[i] % 8) {
   723→          minVecTileSizes[loopNum] = std::max(
   724→              minVecTileSizes[loopNum], 8 / std::gcd(8, operandElemBits[i]));
   725→        }
   726→      }
   727→    }
   728→  }
   729→
   730→  // For each loop starting from the inner-most, clamp vecTileSizes to honor
   731→  // `eachOperandMaxTileBits`, to the extent permitted by `minVecTileSizes`
   732→  // (which is a harder requirement).
   733→  for (int loopNum : llvm::reverse(llvm::seq<int>(0, numLoops))) {
   734→    // Skip 0 vecTileSizes, want to preserve them as 0.
   735→    if (vecTileSizes[loopNum] == 0) {
   736→      continue;
   737→    }
   738→    for (int i : llvm::seq<int>(0, numOperands)) {
   739→      // Check if this operand is concerned with this loop.
   740→      if (!indexingMaps[i].isFunctionOfDim(loopNum)) {
   741→        continue;
   742→      }
   743→      int64_t oldVal = vecTileSizes[loopNum];
   744→      int64_t maxVal = std::max(minVecTileSizes[loopNum],
   745→                                eachOperandMaxTileBits / tileBits[i]);
   746→      int64_t adjustedVal = std::min(oldVal, maxVal);
   747→      // If we are adjusting a tile size, make sure that the adjusted tile size
   748→      // is a power-of-two, as introducing non-power-of-two tile sizes can be a
   749→      // major performance regression, e.g. a 30% e2e regression in MobileNetV2
   750→      // just from a single occurrence in a DepthwiseConv (example discussed
   751→      // below in this comment).
   752→      //
   753→      // We round the adjustedVal to the nearest power of two /below/ not
   754→      // /above/ because doing that could make the entire adjustment a
   755→      // no-operation (e.g. from 8 to 5 back to 8) and then would trigger the
   756→      // tail recursion with halved eachOperandMaxTileBits, which would result
   757→      // in more aggressive tile size limitation. E.g. in MobileNetV2 on AVX-512
   758→      // we have a DepthwiseConv with
   759→      //   vecTileSizes = [1 1 8 16 1 3],
   760→      // without this adjustment, this becomes
   761→      //   vecTileSizes = [1 1 5 16 1 3].
   762→      // If we round this 5 back to 8, letting this function tail-recurse, we
   763→      // end up with this much narrower final result:
   764→      //   vecTileSizes = [1 1 2 16 1 3].
   765→      // It is best to round this 5 to 4, obtaining
   766→      //   vecTileSizes = [1 1 4 16 1 3].
   767→      //
   768→      // The above example also shows that some non-power-of-two tile sizes
   769→      // are not getting adjusted, and should not be rounded to nearest
   770→      // power-of-two: the inner-most dimension size 3 above.
   771→      if (adjustedVal != oldVal) {
   772→        // Round to nearest power of 2, rounding down.
   773→        adjustedVal = 1ll << llvm::Log2_64(adjustedVal);
   774→      }
   775→      vecTileSizes[loopNum] = adjustedVal;
   776→      tileBits[i] *= adjustedVal;
   777→    }
   778→  }
   779→
   780→  // At this point we have satisfied our entry-wise requirements on
   781→  // `vecTileSizes`, but there is still the possibility that the sum of all
   782→  // operand tiles' bit sizes exceeds `allOperandsMaxTileBits`. Tail-recurse
   783→  // with halved `eachOperandMaxTileBits` until that requirement is satisfied.
   784→  // Note that if `eachOperandMaxTileBits` falls below some element type bit
   785→  // width, it will trigger an early-return above, so we don't need to worry
   786→  // about that here.
   787→  if (std::reduce(tileBits.begin(), tileBits.end()) > allOperandsMaxTileBits) {
   788→    limitVectorTileSizes(op, vecTileSizes, eachOperandMaxTileBits / 2,
   789→                         allOperandsMaxTileBits);
   790→  }
   791→}
