    67→bool isLinalgGeneric2DTranspose(linalg::GenericOp genericOp) {
    68→  // Check op has 2 dimensions.
    69→  if (genericOp.getNumLoops() != 2)
    70→    return false;
    71→
    72→  // Check op has single input and output.
    73→  if (genericOp.getNumDpsInputs() != 1 || genericOp.getNumDpsInits() != 1)
    74→    return false;
    75→
    76→  // Check all iterators are parallel.
    77→  if (genericOp.getNumParallelLoops() != genericOp.getNumLoops())
    78→    return false;
    79→
    80→  // Check that the two indexing maps are a permutation of each other.
    81→  SmallVector<AffineMap> indexingMaps = genericOp.getIndexingMapsArray();
    82→  bool isTranspose =
    83→      (indexingMaps[0].isPermutation() && indexingMaps[1].isIdentity()) ||
    84→      (indexingMaps[1].isPermutation() && indexingMaps[0].isIdentity());
    85→  if (!isTranspose)
    86→    return false;
    87→
    88→  // Make sure the region only contains a yield op.
    89→  Block &body = genericOp.getRegion().front();
    90→  if (!llvm::hasSingleElement(body))
    91→    return false;
    92→
    93→  auto yieldOp = cast<linalg::YieldOp>(body.getTerminator());
    94→
    95→  // The yield op should return the block argument corresponding to the input.
    96→  auto yieldArg = dyn_cast<BlockArgument>(yieldOp.getValues()[0]);
    97→  if (!yieldArg || yieldArg.getArgNumber() != 0 || yieldArg.getOwner() != &body)
    98→    return false;
    99→
   100→  return true;

